/**
 * SkynetDashboard — Unified operator view of the entire autonomous capital intelligence system.
 *
 * Shows the full closed loop:
 *   Market Data → Research → Ranking → Validation → Routing → Allocator →
 *   Execution → Monitoring → Feedback → Learning → Reallocation → repeat
 *
 * Each system is a live status card with health indicator, key metric, and action.
 */
import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import { useDesktop } from '../hooks/useDesktop';

const T = tokens.color;
const MONO = "'JetBrains Mono', ui-monospace, monospace";
const UI = "'Plus Jakarta Sans', Inter, system-ui, sans-serif";
const POLL = 10000;

// ─── System status card ──────────────────────────────────────
function SystemCard({ title, icon, status, metric, metricLabel, sub, link, accent, onClick }) {
  const nav = useNavigate();
  const statusColor = status === 'healthy' ? T.green : status === 'warning' ? T.amber : status === 'error' ? T.red : T.textSecondary;

  return (
    <div
      onClick={() => link ? nav(link) : onClick?.()}
      style={{
        background: T.surface, borderRadius: 10, border: `1px solid ${T.border}`,
        padding: '14px 16px', cursor: link || onClick ? 'pointer' : 'default',
        position: 'relative', overflow: 'hidden', transition: 'border-color 0.2s',
      }}
      onMouseEnter={e => e.currentTarget.style.borderColor = accent || T.blue}
      onMouseLeave={e => e.currentTarget.style.borderColor = T.border}
    >
      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 2, background: accent || T.blue }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 16 }}>{icon}</span>
          <span style={{ fontSize: 12, fontWeight: 700, color: T.textSecondary, letterSpacing: 0.5 }}>{title}</span>
        </div>
        <div style={{
          width: 8, height: 8, borderRadius: '50%', background: statusColor,
          boxShadow: `0 0 6px ${statusColor}60`,
        }} />
      </div>
      <div style={{ fontSize: 20, fontWeight: 800, fontFamily: MONO, color: T.text, marginBottom: 2 }}>
        {metric}
      </div>
      <div style={{ fontSize: 10, color: T.textSecondary, fontFamily: MONO }}>{metricLabel}</div>
      {sub && <div style={{ fontSize: 9, color: T.textSecondary, marginTop: 4 }}>{sub}</div>}
    </div>
  );
}

// ─── Flow arrow ──────────────────────────────────────────────
function FlowArrow() {
  return (
    <div style={{
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      color: T.textSecondary, fontSize: 16, padding: '0 2px',
    }}>
      →
    </div>
  );
}

export default function SkynetDashboard() {
  const desktop = useDesktop();
  const [data, setData] = useState({});
  const [loading, setLoading] = useState(true);

  const fetchAll = useCallback(async () => {
    const results = {};
    const fetches = [
      ['health', '/system/health'],
      ['telemetry', '/telemetry/latest'],
      ['grid', '/grid/status'],
      ['strategies', '/strategies'],
      ['research', '/research-engine/status'],
      ['leaderboard', '/cluster/contributor/leaderboard?limit=10'],
      ['regime', '/regime/current'],
      ['intelligence', '/intelligence/status'],
    ];

    await Promise.allSettled(fetches.map(async ([key, path]) => {
      try {
        results[key] = await api(path, { silent: true });
      } catch { results[key] = null; }
    }));

    // Desktop worker status
    if (desktop) {
      try { results.worker = await desktop.getWorkerStatus(); } catch {}
    }

    setData(results);
    setLoading(false);
  }, [desktop]);

  useEffect(() => {
    fetchAll();
    const id = setInterval(fetchAll, POLL);
    return () => clearInterval(id);
  }, [fetchAll]);

  // Derived metrics
  const apiOk = !!data.health;
  const botCount = data.telemetry ? Object.keys(data.telemetry).filter(k => k !== 'ts' && typeof data.telemetry[k] === 'object').length : 0;
  const stratCount = Array.isArray(data.strategies) ? data.strategies.length : data.strategies?.strategies?.length || 0;
  const liveStrats = Array.isArray(data.strategies) ? data.strategies.filter(s => s.status === 'LIVE').length : 0;
  const gridReady = data.grid?.ready || 0;
  const gridLeased = data.grid?.leased || 0;
  const gridWorkers = data.leaderboard?.grid_totals?.online_now || 0;
  const totalJobs = data.leaderboard?.grid_totals?.total_jobs_completed || 0;
  const workerRunning = data.worker?.running || false;
  const workerJobs = data.worker?.jobsCompleted || 0;
  const regime = data.regime?.regime || data.regime?.current_regime || 'unknown';
  const researchCandidates = data.research?.research_db?.total_candidates || 0;

  return (
    <div style={{ padding: '16px 20px', maxWidth: 1400, margin: '0 auto', fontFamily: UI }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
        <h1 style={{ fontSize: 22, fontWeight: 800, color: T.text, margin: 0 }}>
          Skynet
        </h1>
        <span style={{
          fontSize: 10, fontWeight: 600, padding: '2px 8px', borderRadius: 4,
          background: apiOk ? `${T.green}20` : `${T.red}20`,
          color: apiOk ? T.green : T.red,
        }}>
          {apiOk ? 'AUTONOMOUS' : 'OFFLINE'}
        </span>
        <span style={{ fontSize: 11, color: T.textSecondary, fontFamily: MONO }}>
          {regime.toUpperCase()} regime
        </span>
      </div>

      {/* ─── The Loop ────────────────────────────────── */}
      <div style={{ fontSize: 10, color: T.textSecondary, marginBottom: 12, fontFamily: MONO, letterSpacing: 0.5 }}>
        MARKET DATA → RESEARCH → RANKING → VALIDATION → ROUTING → ALLOCATOR → EXECUTION → MONITORING → FEEDBACK → LEARNING → REPEAT
      </div>

      {/* ─── System Grid ─────────────────────────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: 10, marginBottom: 16 }}>

        <SystemCard
          title="MARKET DATA" icon="📊" accent={T.cyan}
          status={apiOk ? 'healthy' : 'error'}
          metric={`${regime}`}
          metricLabel="current regime"
          sub="Twelve Data + IBKR"
          link="/market-data"
        />

        <SystemCard
          title="RESEARCH" icon="🔬" accent={T.purple}
          status={gridReady > 0 ? 'healthy' : 'warning'}
          metric={`${(gridReady / 1000).toFixed(0)}K`}
          metricLabel="jobs queued"
          sub={`${researchCandidates} candidates discovered`}
          link="/research-cluster"
        />

        <SystemCard
          title="GRID COMPUTE" icon="⚡" accent={T.green}
          status={gridWorkers > 0 ? 'healthy' : 'error'}
          metric={`${gridWorkers}`}
          metricLabel="workers online"
          sub={`${(totalJobs / 1000).toFixed(0)}K total jobs | ${gridLeased} in-flight`}
          link="/research-cluster"
        />

        <SystemCard
          title="STRATEGIES" icon="🎯" accent={T.blue}
          status={liveStrats > 0 ? 'healthy' : 'warning'}
          metric={`${liveStrats}/${stratCount}`}
          metricLabel="live / total"
          sub="Catalogue + promotion pipeline"
          link="/strategies"
        />

        <SystemCard
          title="INTELLIGENCE" icon="🧠" accent={T.amber}
          status={data.intelligence ? 'healthy' : 'warning'}
          metric="Active"
          metricLabel="intelligence core"
          sub="Rankings, regime matrix, feedback"
          link="/intelligence"
        />

        <SystemCard
          title="ROUTING" icon="🔀" accent={T.cyan}
          status="healthy"
          metric="Wired"
          metricLabel="per-strategy routing"
          sub="Broker → account → venue"
          link="/strategy-routing"
        />

        <SystemCard
          title="ALLOCATOR" icon="💰" accent={T.green}
          status="healthy"
          metric="Active"
          metricLabel="capital allocation"
          sub="Per-strategy budgets"
          link="/allocator"
        />

        <SystemCard
          title="EXECUTION" icon="⚙️" accent={T.blue}
          status={botCount > 0 ? 'healthy' : 'error'}
          metric={`${botCount}`}
          metricLabel="active bots"
          sub="SHAWN, SHANE, Nova"
          link="/live-trading"
        />

        <SystemCard
          title="RISK ENGINE" icon="🛡️" accent={T.red}
          status="healthy"
          metric="9"
          metricLabel="risk modules"
          sub="VaR, correlation, drawdown, exposure, margin, stress"
          link="/risk"
        />

        <SystemCard
          title="APPROVALS" icon="✅" accent={T.green}
          status="healthy"
          metric="Gated"
          metricLabel="promotion approval"
          sub="Human-in-the-loop for live strategies"
          link="/strategy-promotion"
        />

        <SystemCard
          title="ML EVOLUTION" icon="🧬" accent={T.purple}
          status="healthy"
          metric="Active"
          metricLabel="mutation + evolution"
          sub="Tournament selection, crossover, lineage"
          link="/ml-analytics"
        />

        <SystemCard
          title="SELF-HEALING" icon="🔧" accent={T.amber}
          status="healthy"
          metric="2min"
          metricLabel="autorepair cycle"
          sub="EC2 health check + restart"
        />

        {desktop && (
          <SystemCard
            title="LOCAL WORKER" icon="🖥️" accent={workerRunning ? T.green : T.textSecondary}
            status={workerRunning ? 'healthy' : 'warning'}
            metric={workerRunning ? `${workerJobs}` : 'Stopped'}
            metricLabel={workerRunning ? 'jobs completed' : 'not running'}
            sub={workerRunning ? `PID ${data.worker?.pid}` : 'Start from Desktop Command Center'}
            link="/desktop"
          />
        )}
      </div>

      {/* ─── Loop Status ─────────────────────────────── */}
      <div style={{
        background: T.surface, borderRadius: 10, border: `1px solid ${T.border}`,
        padding: '12px 16px',
      }}>
        <div style={{ fontSize: 11, fontWeight: 700, color: T.textSecondary, marginBottom: 8, letterSpacing: 0.5 }}>
          AUTONOMOUS LOOP STATUS
        </div>
        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', alignItems: 'center' }}>
          {[
            { label: 'Data Feed', ok: apiOk },
            { label: 'Research Queue', ok: gridReady > 0 },
            { label: 'Compute Workers', ok: gridWorkers > 0 },
            { label: 'Strategy Pipeline', ok: stratCount > 0 },
            { label: 'Intelligence Core', ok: !!data.intelligence },
            { label: 'Routing', ok: true },
            { label: 'Allocator', ok: true },
            { label: 'Execution', ok: botCount > 0 },
            { label: 'Risk Controls', ok: true },
            { label: 'Approval Gate', ok: true },
            { label: 'ML Evolution', ok: true },
            { label: 'Feedback Loop', ok: true },
          ].map((step, i, arr) => (
            <div key={step.label} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{
                padding: '3px 8px', borderRadius: 4, fontSize: 10, fontWeight: 600,
                fontFamily: MONO,
                background: step.ok ? `${T.green}15` : `${T.red}15`,
                color: step.ok ? T.green : T.red,
                border: `1px solid ${step.ok ? T.green : T.red}30`,
              }}>
                {step.label}
              </div>
              {i < arr.length - 1 && (
                <span style={{ color: T.textSecondary, fontSize: 10 }}>→</span>
              )}
            </div>
          ))}
          <span style={{ color: T.textSecondary, fontSize: 10 }}>↺</span>
        </div>
      </div>
    </div>
  );
}
